const mysql = require('mysql2');
const path = require('path');

// This forces Node to look for the .env file in the root folder relative to this file
require('dotenv').config({ path: path.resolve(__dirname, '../../.env') });

// DEBUG: Let's see if the variables are actually reaching this file
console.log("--- DB Connection Debug ---");
console.log("DB_USER:", process.env.DB_USER);
console.log("DB_NAME:", process.env.DB_NAME);
console.log("---------------------------");

const db = mysql.createConnection({
    host: process.env.DB_HOST || 'localhost',
    user: process.env.DB_USER,      // Should now show 'root'
    password: process.env.DB_PASS,  // Should now show 'user'
    database: process.env.DB_NAME
});

db.connect((err) => {
    if (err) {
        console.error('❌ Database connection failed: ' + err.stack);
        return;
    }
    console.log('✅ Connected to MySQL successfully!');
});

module.exports = db;